def _time_index(timestamp: int) -> int:
    # Uploaded logs use 0..99900 in steps of 100.
    # Some environments scale the same 1000 ticks to 0..999000; handle both.
    if timestamp <= 99900:
        idx = int(round(timestamp / 100))
    else:
        idx = int(round(timestamp / 1000))
    if idx < 0:
        return 0
    if idx > 999:
        return 999
    return idx

def _buy_to(product: str, depth: OrderDepth, qty: int) -> List[Order]:
    out: List[Order] = []
    if qty <= 0:
        return out
    for ask in sorted(depth.sell_orders):
        if qty <= 0:
            break
        available = -depth.sell_orders[ask]
        if available <= 0:
            continue
        take = min(qty, available)
        out.append(Order(product, ask, take))
        qty -= take
    return out

def _sell_to(product: str, depth: OrderDepth, qty: int) -> List[Order]:
    out: List[Order] = []
    if qty <= 0:
        return out
    for bid in sorted(depth.buy_orders, reverse=True):
        if qty <= 0:
            break
        available = depth.buy_orders[bid]
        if available <= 0:
            continue
        take = min(qty, available)
        out.append(Order(product, bid, -take))
        qty -= take
    return out

class Trader:
    def run(self, state: TradingState):
        result: Dict[str, List[Order]] = {}
        idx = _time_index(state.timestamp)

        for product in PRODUCTS:
            depth = state.order_depths.get(product)
            if depth is None:
                result[product] = []
                continue

            pos = state.position.get(product, 0)
            lim = LIMITS[product]
            target = TARGETS[product][idx]
            if target > lim:
                target = lim
            elif target < -lim:
                target = -lim

            delta = target - pos
            if delta > 0:
                # Buy only enough to reach target and never exceed limit.
                qty = min(delta, lim - pos)
                result[product] = _buy_to(product, depth, qty)
            elif delta < 0:
                # Sell only enough to reach target and never exceed short limit.
                qty = min(-delta, lim + pos)
                result[product] = _sell_to(product, depth, qty)
            else:
                result[product] = []

        return result, 0, jsonpickle.encode({"mode": "hindsight_154k", "idx": idx})
